const products = items
  .map(item => `- ${item.json.title} (Prix: ${item.json.retail_price}€)`)
  .join('\n');

const productIds = items.map(item => item.json.id);
const coverImage = items
  .map(item => typeof item.json.image === 'string' ? item.json.image.trim() : '')
  .find(Boolean) || null;

return [{
  json: {
    products_text: products,
    product_ids: productIds,
    cover_image: coverImage,
  }
}];

const toSlug = (value) => value
  .toLowerCase()
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .replace(/[^a-z0-9]+/g, '-')
  .replace(/(^-|-$)+/g, '');

let aiText = items[0].json.output || items[0].json.text || items[0].json.message?.content || items[0].json.message || '';

if (typeof aiText !== 'string' || !aiText.trim()) {
  throw new Error('La réponse du modèle est vide ou illisible.');
}

aiText = aiText.replace(/```json/gi, '').replace(/```/g, '').trim();

const start = aiText.indexOf('{');
const end = aiText.lastIndexOf('}');
const jsonSlice = start !== -1 && end !== -1 && end > start
  ? aiText.slice(start, end + 1)
  : aiText;

let aiResponse;
try {
  aiResponse = JSON.parse(aiText);
} catch {
  aiResponse = JSON.parse(jsonSlice);
}

const preparedData = $('Code : Préparer Data pour LLM').first().json;
const productIds = preparedData.product_ids || [];
const coverImage = preparedData.cover_image || null;
const title = typeof aiResponse.title === 'string' ? aiResponse.title.trim() : '';
const summarySource = typeof aiResponse.excerpt === 'string'
  ? aiResponse.excerpt
  : typeof aiResponse.summary === 'string'
    ? aiResponse.summary
    : '';
const content = typeof aiResponse.content === 'string' ? aiResponse.content.trim() : '';
const slugSource = typeof aiResponse.slug === 'string' ? aiResponse.slug : title;
const safeSlug = toSlug(slugSource || title || `article-${Date.now()}`);

return [{
  json: {
    title: title || 'Article KOKTEK',
    slug: safeSlug,
    summary: summarySource.trim(),
    content,
    cover_image: coverImage,
    product_ids: productIds,
  }
}];

